let itemData = {{workflowparams:itemData}}

if (!itemData) {
  itemData = {{node:get_node_MuNnpfmj.data.data}}
}

const isMovingInv = {{workflowparams:isMovingInv}} ?? 0;

return {
  itemData: itemData,
  isMovingInv: isMovingInv
}

// For quantities - 3 decimal places
const roundQty = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(3));
};

const itemData = {{node:code_node_3XzQSsce.data.itemData}}

let altQty = roundQty(parseFloat({{workflowparams:quantity}}));
let baseQty = altQty;
let altUOM = {{workflowparams:material_uom}} || itemData.based_uom;
let baseUOM = itemData.based_uom

const tableUomConversion = itemData.table_uom_conversion

if (
Array.isArray(tableUomConversion) &&
  tableUomConversion.length > 0
) {
  const uomConversion = tableUomConversion.find(
    (conv) => conv.alt_uom_id === altUOM
  );

  if (uomConversion) {
    baseQty = roundQty(altQty * uomConversion.base_qty);

  }
}

const costingMethod = itemData.material_costing_method

return {
  altQty: altQty,
  baseQty: baseQty,
  altUOM: altUOM,
  baseUOM: baseUOM,
  costingMethod: costingMethod,
}

// For quantities - 3 decimal places
const roundQty = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(3));
};

// For prices - 4 decimal places
const roundPrice = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(4));
};

const baseQty = {{node:code_node_mvszWJ8p.data.baseQty}}
let unitPrice = roundPrice({{workflowparams:unit_price}})
let totalPrice = roundPrice(unitPrice * baseQty)

if ({{workflowparams:transaction_type}} === 'GRN') {
  const poQuantity = roundQty(parseFloat({{workflowparams:po_quantity}}) || 0);
  const totalAmount = roundPrice(parseFloat({{workflowparams:po_amount}}) || 0);
  const conversion = roundQty(baseQty / parseFloat({{workflowparams:quantity}}))
  const exchangeRate = {{workflowparams:exchange_rate}} || 1

  const pricePerUnit = poQuantity > 0 ? roundPrice(totalAmount / poQuantity) : 0;
  const costPrice = roundPrice((pricePerUnit / conversion) * exchangeRate);

  unitPrice = costPrice
  totalPrice = roundPrice(unitPrice * baseQty)
}

return {
  unitPrice: unitPrice,
  totalPrice: totalPrice
}

// For prices - 4 decimal places
const roundPrice = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(4));
};

const itemData = {{node:code_node_3XzQSsce.data.itemData}}

let unitPrice = roundPrice(itemData.purchase_unit_price)
let totalPrice = roundPrice(unitPrice * {{node:code_node_mvszWJ8p.data.baseQty}})

return {
  unitPrice: unitPrice,
  totalPrice: totalPrice
}

const transactionType = {{workflowparams:transaction_type}}
const costingMethod = {{node:code_node_mvszWJ8p.data.costingMethod}}
let unitPrice = {{workflowparams:unit_price}}
let totalPrice = unitPrice * {{node:code_node_mvszWJ8p.data.baseQty}}

if (transactionType !== "LOT") {
  if (costingMethod === "First In First Out" || costingMethod === "Weighted Average") {
    unitPrice = {{node:code_node_3SC3WFhc.data.unitPrice}}
    totalPrice = {{node:code_node_3SC3WFhc.data.totalPrice}}
  } else if (costingMethod === "Fixed Cost") {
    unitPrice = {{node:code_node_BDhmDHrJ.data.unitPrice}}
    totalPrice = {{node:code_node_BDhmDHrJ.data.totalPrice}}
  }
}

return {
  unitPrice: Number(unitPrice.toFixed(4)),
  totalPrice: Number(totalPrice.toFixed(4))
}

const transactionType = {{workflowparams:transaction_type}}
let batchId = null

if ({{workflowparams:batch_number}} !== "-" && {{workflowparams:batch_number}} && !{{workflowparams:batch_id}}){
  batchId = {{node:add_node_F9KqZLfd.data.id}}[0]
} else {
  batchId = {{workflowparams:batch_id}}
}

return {
  batchId: batchId
}

// For quantities - 3 decimal places
const roundQty = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(3));
};

let block_qty = 0,
  reserved_qty = 0,
  unrestricted_qty = 0,
  qualityinsp_qty = 0,
  intransit_qty = 0;

const quantity = roundQty(parseFloat({{node:code_node_mvszWJ8p.data.baseQty}} || 0));
const invCategory = {{workflowparams:inventory_category}}

if (invCategory === "Blocked") {
  block_qty = quantity;
} else if (invCategory === "Reserved") {
  reserved_qty = quantity;
} else if (invCategory === "Unrestricted") {
  unrestricted_qty = quantity;
} else if (invCategory === "Quality Inspection") {
  qualityinsp_qty = quantity;
} else if (invCategory === "In Transit") {
  intransit_qty = quantity;
} else {
  unrestricted_qty = quantity;
}

const balance_quantity =
  block_qty + reserved_qty + unrestricted_qty + qualityinsp_qty + intransit_qty;

return {
  block_qty: block_qty,
  reserved_qty: reserved_qty,
  unrestricted_qty: unrestricted_qty,
  qualityinsp_qty: qualityinsp_qty,
  intransit_qty: intransit_qty,
  balance_quantity: balance_quantity,
};

const roundQty = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(3));
};

const rawItemBatch = {{node:get_node_kePN6D3V.data.data}}
const itemBatchData = (Array.isArray(rawItemBatch) ? rawItemBatch[0] : rawItemBatch) || {}

const getRemarkValue = (newValue, existingValue) => {
  return (newValue != null && newValue !== existingValue) ? newValue : (existingValue || "")
}

const remark = getRemarkValue({{workflowparams:remark}}, itemBatchData.remark)
const remark2 = getRemarkValue({{workflowparams:remark2}}, itemBatchData.remark2)
const remark3 = getRemarkValue({{workflowparams:remark3}}, itemBatchData.remark3)

// Final batch qty values (current + add) for the Update Batch Balance Data node
const balanceData = {{node:code_node_aFO7peip.data}}

const block_qty = roundQty(roundQty(itemBatchData.block_qty || 0) + roundQty(balanceData.block_qty || 0))
const reserved_qty = roundQty(roundQty(itemBatchData.reserved_qty || 0) + roundQty(balanceData.reserved_qty || 0))
const unrestricted_qty = roundQty(roundQty(itemBatchData.unrestricted_qty || 0) + roundQty(balanceData.unrestricted_qty || 0))
const qualityinsp_qty = roundQty(roundQty(itemBatchData.qualityinsp_qty || 0) + roundQty(balanceData.qualityinsp_qty || 0))
const intransit_qty = roundQty(roundQty(itemBatchData.intransit_qty || 0) + roundQty(balanceData.intransit_qty || 0))
const balance_quantity = roundQty(roundQty(itemBatchData.balance_quantity || 0) + roundQty(balanceData.balance_quantity || 0))

return {
  remark: remark,
  remark2: remark2,
  remark3: remark3,
  block_qty: block_qty,
  reserved_qty: reserved_qty,
  unrestricted_qty: unrestricted_qty,
  qualityinsp_qty: qualityinsp_qty,
  intransit_qty: intransit_qty,
  balance_quantity: balance_quantity
}

const roundQty = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(3));
};

const rawBalance = {{node:get_node_dzqHveJM.data.data}}
const existingBalance = (Array.isArray(rawBalance) ? rawBalance[0] : rawBalance) || {}

const balanceData = {{node:code_node_aFO7peip.data}}

const block_qty = roundQty(roundQty(existingBalance.block_qty || 0) + roundQty(balanceData.block_qty || 0))
const reserved_qty = roundQty(roundQty(existingBalance.reserved_qty || 0) + roundQty(balanceData.reserved_qty || 0))
const unrestricted_qty = roundQty(roundQty(existingBalance.unrestricted_qty || 0) + roundQty(balanceData.unrestricted_qty || 0))
const qualityinsp_qty = roundQty(roundQty(existingBalance.qualityinsp_qty || 0) + roundQty(balanceData.qualityinsp_qty || 0))
const intransit_qty = roundQty(roundQty(existingBalance.intransit_qty || 0) + roundQty(balanceData.intransit_qty || 0))
const balance_quantity = roundQty(roundQty(existingBalance.balance_quantity || 0) + roundQty(balanceData.balance_quantity || 0))

return {
  block_qty: block_qty,
  reserved_qty: reserved_qty,
  unrestricted_qty: unrestricted_qty,
  qualityinsp_qty: qualityinsp_qty,
  intransit_qty: intransit_qty,
  balance_quantity: balance_quantity
}

const fifoResponse = {{node:search_node_RjYmYDlj.data}}
// Determine next sequence number
let sequenceNumber = 1;

if (
  fifoResponse.data &&
  Array.isArray(fifoResponse.data) &&
  fifoResponse.data.length > 0
) {
  const existingSequences = fifoResponse.data.map((doc) =>
    parseInt(doc.fifo_sequence || 0, 10)
  );
  sequenceNumber = Math.max(...existingSequences, 0) + 1;
}

return {
  sequenceNumber: sequenceNumber
}

// For quantities - 3 decimal places
const roundQty = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(3));
};

// For prices - 4 decimal places
const roundPrice = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(4));
};

const waData = {{node:search_node_sE4TyFdE.data.data}}
const baseQty ={{node:code_node_mvszWJ8p.data.baseQty}}

// Sort records by date, newest first
waData.sort((a, b) => {
  if (a.created_at && b.created_at) {
    return new Date(b.created_at) - new Date(a.created_at);
  }
  return 0;
});

const latestWa = waData[0];
const waCostPrice = roundPrice(latestWa.wa_cost_price);
const waQuantity = roundQty(latestWa.wa_quantity);
const newWaQuantity = roundQty(waQuantity + baseQty);

const costPrice = {{node:code_node_BzebhJnQ.data.unitPrice}}

const calculatedWaCostPrice = roundPrice(
  (waCostPrice * waQuantity + costPrice * baseQty) / newWaQuantity
);

const newWaCostPrice = roundPrice(calculatedWaCostPrice);

return {
  newWaQuantity: newWaQuantity,
  newWaCostPrice: newWaCostPrice,
  latestWaId: latestWa.id
}
